const configured = process.env.DDISCOVER_N8N_SOURCES_JSON;
const fallbackSources = [
  {
    sourceKey: 'objekt-klein-a-events',
    name: 'Objekt klein a events',
    sourceType: 'calendar_page',
    url: 'https://objektkleina.com/events'
  }
];

let sources = fallbackSources;
if (configured && configured.trim()) {
  try {
    sources = JSON.parse(configured);
  } catch (error) {
    throw new Error(`DDISCOVER_N8N_SOURCES_JSON is not valid JSON: ${error.message}`);
  }
}

if (!Array.isArray(sources) || sources.length === 0) {
  throw new Error('No ingestion sources configured.');
}

return sources.map((source) => ({ json: source }));

function stripHtml(html) {
  return String(html)
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

const output = [];
for (const item of $input.all()) {
  const source = item.json;
  if (!source.url) {
    throw new Error(`Source ${source.name || source.sourceKey || 'unknown'} has no url.`);
  }

  const html = await this.helpers.httpRequest({
    method: 'GET',
    url: source.url,
    headers: {
      accept: 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
      'user-agent': 'DDiscoverBot/0.1 (+https://github.com/royalcaster/ddiscover)'
    },
    timeout: 30000,
    json: false
  });
  const text = stripHtml(html).slice(0, 45000);
  output.push({
    json: {
      source,
      fetchedAt: Date.now(),
      pageText: text
    }
  });
}

return output;

const model = process.env.DDISCOVER_OPENAI_MODEL || 'gpt-4.1-mini';
const schema = {
  type: 'object',
  additionalProperties: false,
  properties: {
    venues: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          sourceKey: { type: ['string', 'null'] },
          name: { type: 'string' },
          addressLine: { type: ['string', 'null'] },
          city: { type: ['string', 'null'] },
          websiteUrl: { type: ['string', 'null'] },
          category: { type: ['string', 'null'] },
          evidenceSnippets: { type: 'array', items: { type: 'string' } },
          warnings: { type: 'array', items: { type: 'string' } },
          confidence: { type: 'number' }
        },
        required: ['sourceKey', 'name', 'addressLine', 'city', 'websiteUrl', 'category', 'evidenceSnippets', 'warnings', 'confidence']
      }
    },
    events: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          sourceKey: { type: ['string', 'null'] },
          title: { type: 'string' },
          description: { type: ['string', 'null'] },
          startsAtIso: { type: 'string' },
          endsAtIso: { type: ['string', 'null'] },
          venueName: { type: 'string' },
          venueCandidateSourceKey: { type: ['string', 'null'] },
          sourceUrl: { type: 'string' },
          ticketUrl: { type: ['string', 'null'] },
          imageSourceUrl: { type: ['string', 'null'] },
          tags: { type: 'array', items: { type: 'string' } },
          evidenceSnippets: { type: 'array', items: { type: 'string' } },
          warnings: { type: 'array', items: { type: 'string' } },
          confidence: { type: 'number' }
        },
        required: ['sourceKey', 'title', 'description', 'startsAtIso', 'endsAtIso', 'venueName', 'venueCandidateSourceKey', 'sourceUrl', 'ticketUrl', 'imageSourceUrl', 'tags', 'evidenceSnippets', 'warnings', 'confidence']
      }
    }
  },
  required: ['venues', 'events']
};

return $input.all().map((item) => ({
  json: {
    source: item.json.source,
    fetchedAt: item.json.fetchedAt,
    request: {
      model,
      messages: [
        {
          role: 'system',
          content: 'You extract nightlife venue and event candidates for DDiscover. Return only structured JSON. Use Europe/Berlin local time. Do not invent events, venues, URLs, coordinates, or ticket links. Include short evidence snippets copied from the page text. Confidence must be 0..1.'
        },
        {
          role: 'user',
          content: `Source name: ${item.json.source.name}\nSource URL: ${item.json.source.url}\nSource type: ${item.json.source.sourceType}\n\nExtract future Dresden nightlife events and their venue candidates from this page text. Ignore navigation, cookie banners, historical events, and vague teasers without a date.\n\nPAGE TEXT:\n${item.json.pageText}`
        }
      ],
      response_format: {
        type: 'json_schema',
        json_schema: {
          name: 'ddiscover_ingestion_candidates',
          strict: true,
          schema
        }
      },
      temperature: 0.1
    }
  }
}));

const output = [];
for (const item of $input.all()) {
  if (!process.env.OPENAI_API_KEY) {
    throw new Error('OPENAI_API_KEY is required.');
  }

  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: {
      authorization: `Bearer ${process.env.OPENAI_API_KEY}`,
      'content-type': 'application/json'
    },
    body: item.json.request,
    json: true,
    timeout: 60000
  });

  const content = response?.choices?.[0]?.message?.content;
  if (!content) {
    throw new Error('OpenAI response did not contain message content.');
  }

  let extracted;
  try {
    extracted = JSON.parse(content);
  } catch (error) {
    throw new Error(`OpenAI response content was not valid JSON: ${error.message}`);
  }

  output.push({
    json: {
      source: item.json.source,
      fetchedAt: item.json.fetchedAt,
      extracted
    }
  });
}
return output;

function clean(value) {
  if (value === null || value === undefined || value === '') return undefined;
  return value;
}

function toTimestamp(iso, label) {
  const timestamp = Date.parse(iso);
  if (!Number.isFinite(timestamp)) {
    throw new Error(`Invalid ${label}: ${iso}`);
  }
  return timestamp;
}

return $input.all().map((item) => {
  const source = item.json.source;
  const extracted = item.json.extracted;
  const venues = (extracted.venues || []).map((venue) => ({
    sourceKey: clean(venue.sourceKey),
    name: venue.name,
    addressLine: clean(venue.addressLine),
    city: clean(venue.city) || 'Dresden',
    websiteUrl: clean(venue.websiteUrl),
    category: clean(venue.category),
    evidenceSnippets: venue.evidenceSnippets || [],
    warnings: venue.warnings || [],
    confidence: venue.confidence
  }));
  const events = (extracted.events || []).map((event) => ({
    sourceKey: clean(event.sourceKey),
    title: event.title,
    description: clean(event.description),
    startsAt: toTimestamp(event.startsAtIso, 'startsAtIso'),
    endsAt: event.endsAtIso ? toTimestamp(event.endsAtIso, 'endsAtIso') : undefined,
    venueName: event.venueName,
    venueCandidateSourceKey: clean(event.venueCandidateSourceKey),
    sourceUrl: event.sourceUrl || source.url,
    ticketUrl: clean(event.ticketUrl),
    imageSourceUrl: clean(event.imageSourceUrl),
    tags: event.tags || [],
    evidenceSnippets: event.evidenceSnippets || [],
    warnings: event.warnings || [],
    confidence: event.confidence
  }));

  return {
    json: {
      source: {
        sourceKey: source.sourceKey,
        name: source.name,
        sourceType: source.sourceType,
        url: source.url,
        fetchedAt: item.json.fetchedAt
      },
      venues,
      events
    }
  };
});

const output = [];
for (const item of $input.all()) {
  if (!process.env.DDISCOVER_CONVEX_SITE_URL) {
    throw new Error('DDISCOVER_CONVEX_SITE_URL is required, for example https://your-deployment.convex.site');
  }
  if (!process.env.DDISCOVER_INGESTION_TOKEN) {
    throw new Error('DDISCOVER_INGESTION_TOKEN is required.');
  }

  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: `${process.env.DDISCOVER_CONVEX_SITE_URL.replace(/\/+$/, '')}/ingestion/candidates`,
    headers: {
      authorization: `Bearer ${process.env.DDISCOVER_INGESTION_TOKEN}`,
      'content-type': 'application/json'
    },
    body: item.json,
    json: true,
    timeout: 30000
  });

  output.push({
    json: {
      source: item.json.source,
      result
    }
  });
}
return output;
